const { username, password } = $input.item.json.body || {};
const { timingSafeEqual, createHmac } = require('crypto');

function safeEqual(a, b) {
  const aBuf = Buffer.from(String(a || ''));
  const bBuf = Buffer.from(String(b || ''));
  if (aBuf.length !== bBuf.length) return false;
  return timingSafeEqual(aBuf, bBuf);
}

const validUser = safeEqual(username, $env.N8N_AUTH_USER);
const validPass = safeEqual(password, $env.N8N_AUTH_PASS);

if (!validUser || !validPass) {
  $input.item.json.authValid = false;
  return $input.item;
}

const secret = $env.JWT_SECRET;
const now = Math.floor(Date.now() / 1000);
const header = Buffer.from(JSON.stringify({ alg: 'HS256', typ: 'JWT' })).toString('base64url');
const payload = Buffer.from(JSON.stringify({ sub: username, iat: now, exp: now + 28800 })).toString('base64url');
const sig = createHmac('sha256', secret).update(`${header}.${payload}`).digest('base64url');

$input.item.json.authValid = true;
$input.item.json.token = `${header}.${payload}.${sig}`;
$input.item.json.expiresIn = 28800;
return $input.item;
